---@class LFightReportGetter
local LFightReportGetter = LxClass("LFightReportGetter", nil)

local PJX = CardEHT
local PJXProtoMessage = PJX.ProtoMessage

LXImport(".LFightPbParser")
LFightReportGetter.REQUESTING = 1
LFightReportGetter.FINISH = 2

function LFightReportGetter:LFightReportGetter()
    self._state = -1
    self._retryCnt = 0
    self._retryMax = 1
    self._timeOut = 3
end
--[[
reportInfo = {
reportId,
reportUrl,
serverId,
}
]]


function LFightReportGetter:Start(reportInfo)

    self._key = reportInfo.key
    self._startTime = self:GetCurTime()

    self._reportId = reportInfo.reportId
    self._serverId = reportInfo.serverId
    self._callback = reportInfo.callback
    self._failCall = reportInfo.failCall
    self._combatType = reportInfo.combatType


    if self._serverId == gLGameLogin:GetActualServerId() then
        self._reportUrl = gLGameLogin:GetHttpReportUrl()
    else
        local reportUrl = gModelBattle:GetReportUrlByServerId(self._serverId)
        if reportUrl then
            self._reportUrl = reportUrl
        else
            LServerUtil.QueryServerDetailIgnorePackageIdFromWeb(function (...)
                self:OnReportUrlRet(...)
            end,self._serverId)

            return
        end
    end

    self:StartRequest()

end

function LFightReportGetter:OnReportUrlRet(bOk,ret,result,url)
    if self:IsDestroy() then return end
    local combatType = self._combatType
    if bOk then
        gModelBattle:CacheReportUrl(self._serverId,result.httpReport)
        self._reportUrl = result.httpReport
        self:StartRequest()
    else
        if combatType then
            gModelBattle:RecordVideoBattleLife(combatType,false)
        end

        self._isError = true

        if self._failCall then
            self._failCall()
        end
    end
end

function LFightReportGetter:StartRequest()
    self._isPbData = self:IsPbData()

    if self._state == LFightReportGetter.FINISH then
        if self._callback then
            self._callback(self._reportTable)
        end
        return
    elseif self._state == LFightReportGetter.REQUESTING then
        return
    end
    self:RequestWebReport()
end

function LFightReportGetter:IsPbData()
    local s,e = string.find(self._reportId,"pb")
    if s and e then
        return true
    end
    return false
end

function LFightReportGetter:RequestWebReport()
    self._state = LFightReportGetter.REQUESTING

    self._reqTime = self:GetCurTime()
    local reportId = self._reportId
    local httpReportUrl = self._reportUrl
    local serverId = self._serverId

    local root = string.split(reportId,"-") or {}
    root = root[1] or "inst"

    if self._isPbData then
        local urlList = {string.format("%s%s/%s/%s.json",httpReportUrl,serverId,root,reportId)}
        self:PbWebRequest(urlList,reportId)
    else
        local reqUrl = string.format("%s%s/%s", httpReportUrl, serverId, root)
        local urlSuffix = string.format("/%s.json", reportId)
        self:JsonWebRequest(reqUrl,urlSuffix,reportId)
    end
end

function LFightReportGetter:PbWebRequest(urlList,reportId)
    LxHttpHelper.DoWebDownFile(urlList, function(url, ret, result, progress, bytes)
        if self:IsDestroy() then return end
        if (ret == CS.YXWebRet.ok) then
            local msgId = LProtoHelper.GetProtoId("CombatReportResp")
            local protoReader = PJXProtoMessage.New()
            protoReader:SetMessage(bytes)
            local str = protoReader:GetMessage()

            if self._frameParser then
                self._frameParser:Destroy()
            end

            self._frameParser= LFightPbParser:New()
            self._frameParser:ParsePb(msgId,str,function (reportTable)
                if self:IsDestroy() then return end
                --local reportTable = LProtoHelper.ConvertToProto(msgId,protoReader:ToLuaByteBuffer())
                if (CS.IsUnityEdit()) then
                    gLFightManager:SavePbReportToFile(reportId,bytes)
                    local tbl = LProtoHelper.ProtoToPureTable(reportTable)
                    local str = JSON.encode(tbl)
                    gLFightManager:SaveReportToFile(reportId.."tojson",str)
                end

                self._reportTable = reportTable
                self._state = LFightReportGetter.FINISH
                if self._callback then
                    self._callback(reportTable)
                end
            end)

            self:StopRetry()
        elseif ret == CS.YXWebRet.Error then
            GF.ShowMessage(ccClientText(10153))
            local combatType = self._combatType
            if combatType then
                gModelBattle:RecordVideoBattleLife(combatType,false)
            end

            self._isError = true

            if self._failCall then
                self._failCall()
            end

            --超时的过几s后重新请求一次
        elseif ret == CS.YXWebRet.Timeout then
            if self._retryCnt < self._retryMax then
                self:StartDelayRequest()
            else
                local combatType = self._combatType
                if combatType then
                    gModelBattle:RecordVideoBattleLife(combatType,false)
                end

                if self._failCall then
                    self._failCall()
                end
            end
        end
    end, true, 1)
end


function LFightReportGetter:JsonWebRequest(reqUrl,urlSuffix,reportId)

    LxHttpHelper.DoWebRequestURL(nil, { reqUrl }, urlSuffix, function(ret, result, url)
        if self:IsDestroy() then return end
        if (ret == CS.YXWebRet.ok) then
            if (CS.IsUnityEdit()) then
                gLFightManager:SaveReportToFile(reportId,result)
            end

            local reportTable = JSON.decode(result)
            self._reportTable = reportTable
            self._state = LFightReportGetter.FINISH

            if self._callback then
                self._callback(reportTable)
            end

            self:StopRetry()
        elseif ret == CS.YXWebRet.Error then --拉不到数据，统一弹提示
            GF.ShowMessage(ccClientText(10153))

            local combatType = self._combatType
            if combatType then
                gModelBattle:RecordVideoBattleLife(combatType,false)
            end

            self._isError = true

            if self._failCall then
                self._failCall()
            end

        elseif ret == CS.YXWebRet.Timeout then --超时的过几s后重新请求一次
            if self._retryCnt < self._retryMax then
                self:StartDelayRequest()
            else
                if self._failCall then
                    self._failCall()
                end
            end
        end
    end, true, 1)
end

function LFightReportGetter:StartDelayRequest()
    if not self._timer then
        self._timer = LxTimer:New()
    end
    self._retryCnt = self._retryCnt + 1
    local key = "delayRequest"
    local delayTime = 1
    self._timer:TimerRemoveByKey(key)
    self._timer:TimerCreate(key,function(...)
        self:RequestWebReport()
    end,delayTime,false,1)
end

function LFightReportGetter:StopRetry()
    if not self._timer then
        return
    end
    self._timer:TimerRemoveByKey("delayRequest")
end
-----------------------------------------------------------------
function LFightReportGetter:IsDestroy()
    return self._isDestroy
end

function LFightReportGetter:Destroy()

    if self._timer  then
        self._timer:Destroy()
        self._timer = nil
    end

    if self._frameParser then
        self._frameParser:Destroy()
    end

    table.removeall(self)
    self._isDestroy = true
end

function LFightReportGetter:CanReplace()
    if self._isDestroy then
        return true
    end

    if self._isError then
        return true
    end

    if self:CheckTimeOut() then
        return true
    end

    if self:IsFinish() then
        return true
    end


    return false
end

function LFightReportGetter:CheckTimeOut()
    if self._state == LFightReportGetter.REQUESTING then
        local time = self:GetCurTime()
        local timeOut = self._timeOut
        local reqTime = self._reqTime
        if time - reqTime > timeOut then
            return true
        end
    end
    return false
end

function LFightReportGetter:GetCurTime()
    return GetTimestamp()
end

function LFightReportGetter:IsFinish()
    return self._state == LFightReportGetter.FINISH
end


function LFightReportGetter:GetReportTable()
    return self._reportTable
end

---已缓存时间，超出可删除缓存
function LFightReportGetter:GetStartTime()
    return self._startTime or GetTimestamp()
end

function LFightReportGetter:GetKey()
    return self._key
end

return LFightReportGetter